// n8n Postgres v2.5 splittet queryReplacement an Kommas. Body-JSON enthaelt
// jedoch Kommas — daher base64-encoden und in SQL via decode() zurueckholen.
const body = $input.first().json.body || {};
const b64 = (v) => Buffer.from(JSON.stringify(v ?? null), 'utf8').toString('base64');
return [{ json: { body_b64: b64(body) } }];
